/// <summary>
/// Runtime oracle for the L3-batch-basic eval case (docs/AGENT_EVAL_LOOP.md §6.3).
///
/// The case asks the agent to build a SysOperation batch job (DataContract +
/// Service + Controller + menu item) whose Service exposes a pure, deterministic
/// helper: the effective batch size is the requested batch size scaled by the
/// priority factor. This test constructs the contract and service directly
/// (bypassing the controller/dialog plumbing, same as a real unit test would)
/// and asserts the arithmetic — a golden diff can confirm the method exists with
/// the right signature, but not that the multiplication is correct.
///
/// Run via `run_systest_class` with className = EvalL3BatchCalcTest.
/// </summary>
class EvalL3BatchCalcTest extends SysTestCase
{
}

Method.Source:
/// <summary>
/// 10 * 3 = 30.
/// </summary>
[SysTestCheckInTestAttribute]
public void testEffectiveBatchSizeMultipliesByPriorityFactor()
{
    ConDemoBatchContract contract = new ConDemoBatchContract();
    contract.parmBatchSize(10);
    contract.parmPriorityFactor(3);

    ConDemoBatchService service = new ConDemoBatchService();
    int result = service.calculateEffectiveBatchSize(contract);

    this.assertEquals(30, result);
}

/// <summary>
/// Determinism across inputs: 7 * 5 = 35.
/// </summary>
[SysTestCheckInTestAttribute]
public void testEffectiveBatchSizeWithDifferentInputs()
{
    ConDemoBatchContract contract = new ConDemoBatchContract();
    contract.parmBatchSize(7);
    contract.parmPriorityFactor(5);

    ConDemoBatchService service = new ConDemoBatchService();
    int result = service.calculateEffectiveBatchSize(contract);

    this.assertEquals(35, result);
}
